import{_ as i,o as s,c as a,a6 as t}from"./chunks/framework.UYVGz2W_.js";const k=JSON.parse('{"title":"Open Source Setup","description":"","frontmatter":{},"headers":[],"relativePath":"installation/index.md","filePath":"installation/index.md"}'),n={name:"installation/index.md"};function l(r,e,h,o,d,p){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="open-source-setup" tabindex="-1">Open Source Setup <a class="header-anchor" href="#open-source-setup" aria-label="Permalink to “Open Source Setup”">​</a></h1><h2 id="cloud-hosting" tabindex="-1">Cloud Hosting <a class="header-anchor" href="#cloud-hosting" aria-label="Permalink to “Cloud Hosting”">​</a></h2><p>If your version of Kitsu is hosted and maintained by CGWire, you don&#39;t have anything to install. Simply connect to the URL provided to you to start using Kitsu!</p><h2 id="self-hosting" tabindex="-1">Self-Hosting <a class="header-anchor" href="#self-hosting" aria-label="Permalink to “Self-Hosting”">​</a></h2><p>To run properly, Kitsu requires Zou, the database API. Information related to the installation of both modules is located in the Zou installation documentation.</p><ul><li><a href="https://zou.cg-wire.com/" target="_blank" rel="noreferrer">Deploying Zou</a></li><li><a href="https://zou.cg-wire.com/#deploying-kitsu" target="_blank" rel="noreferrer">Deploying Kitsu</a></li></ul><p>If you have technical skills, you can run Kitsu/Zou through Docker to try it out:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 80:80</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cgwire</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cgwire/cgwire</span></span></code></pre></div><p>Then you can access Kitsu through <a href="http://localhost" target="_blank" rel="noreferrer">http://localhost</a>.</p><h2 id="development-environment" tabindex="-1">Development Environment <a class="header-anchor" href="#development-environment" aria-label="Permalink to “Development Environment”">​</a></h2><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h3><p>Prior to setting up the Kitsu development environment, make sure you have the following elements installed:</p><ul><li><a href="https://nodejs.org" target="_blank" rel="noreferrer">Node.js</a> &gt;= 20.18</li><li>A <a href="https://zou.cg-wire.com/development/" target="_blank" rel="noreferrer">Zou development instance</a> up and running on port 5000</li><li>A <a href="https://zou.cg-wire.com/development/" target="_blank" rel="noreferrer">Zou Events development instance</a> up and running on port 5001 (optional)</li></ul><h3 id="using-docker-image" tabindex="-1">Using Docker Image <a class="header-anchor" href="#using-docker-image" aria-label="Permalink to “Using Docker Image”">​</a></h3><p>You can use our <a href="https://hub.docker.com/r/cgwire/cgwire" target="_blank" rel="noreferrer">Docker image</a>, but you will need to set two environment variables:</p><ul><li><code>KITSU_API_TARGET</code> (default: <code>http://localhost:5000</code>): The URL where the API can be reached.</li><li><code>KITSU_EVENT_TARGET</code> (default: <code>http://localhost:5001</code>): The URL where the event stream can be reached.</li></ul><p>In that case, run the development environment with the following command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KITSU_API_TARGET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost/api</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KITSU_EVENT_TARGET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>The credentials for the Docker image are: <a href="mailto:admin@example.com" target="_blank" rel="noreferrer">admin@example.com</a> / mysecretpassword</p><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to “Development”">​</a></h2><p>To start modifying Kitsu, clone the repository:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/cgwire/kitsu.git</span></span></code></pre></div><p>Then download the dependencies:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kitsu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>Finally, start the development environment and view the results at <code>http://localhost:8080</code>:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>Any changes will automatically update the page.</p><h2 id="build" tabindex="-1">Build <a class="header-anchor" href="#build" aria-label="Permalink to “Build”">​</a></h2><p>To build your code, run this command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to “Tests”">​</a></h2><p>Run tests with the following command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test:unit</span></span></code></pre></div><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to “Architecture”">​</a></h2><p>Kitsu is based on the <a href="https://vuejs.org/guide/" target="_blank" rel="noreferrer">Vue.js</a> framework. The Vue.js documentation is exhaustive and very clear. We encourage you to read it before making significant changes to the code.</p><p>The architecture is based on <a href="https://vuex.vuejs.org" target="_blank" rel="noreferrer">Vuex</a> and <a href="https://router.vuejs.org" target="_blank" rel="noreferrer">vue-router</a>. Their documentation is also very good, and we recommend reading it. The main idea is that:</p><ul><li>URL routes give the main context.</li><li>Views are described in components through HTML, CSS, and small pieces of JavaScript.</li><li>Shared state is stored inside stores, which are modified through mutations (a kind of event bus to request state changes) and actions.</li><li>Actions are similar to mutations but allow asynchronous operations. Mainly, actions fire mutations and send requests to the server.</li><li>Stores provide getters to access state properties from components.</li><li>Local change logic is kept inside components.</li><li>Getters, actions, and mutations must be testable without a browser.</li></ul>`,37)])])}const g=i(n,[["render",l]]);export{k as __pageData,g as default};
